import { z } from 'zod';
import dotenv from 'dotenv';

dotenv.config();

const envSchema = z.object({
  PORT: z.string().nonempty(),
  MONGO_URI: z.string().url(),
  JWT_SECRET: z.string().min(32),
  RATE_LIMIT_MAX: z
    .string()
    .transform(val => parseInt(val, 10))
    .refine(val => val > 0, { message: "Must be greater than 0" }),
  RATE_LIMIT_WINDOW: z
    .string()
    .transform(val => parseInt(val, 10))
    .refine(val => val > 0, { message: "Must be a valid time window" }),
});

const validatedEnv = envSchema.parse(process.env);

export default validatedEnv;

import { Request, Response, NextFunction } from 'express';
import { ZodError } from 'zod';
import { logger } from '../utils/logger';

export const errorHandler = (err: unknown, req: Request, res: Response, next: NextFunction) => {
  if (err instanceof ZodError) {
    return res.status(400).json({
      error: 'Validation Error',
      details: err.errors,
    });
  }

  logger.error(`Error: ${err instanceof Error ? err.message : err}`);

  res.status(500).json({
    error: 'Internal Server Error',
  });
};

import helmet from 'helmet';
import cors from 'cors';
import rateLimit from 'express-rate-limit';
import express, { Request, Response, NextFunction } from 'express';
import validatedEnv from '../config/env';

const app = express();

const corsOptions = {
  origin: ['https://example.com'], // replace with actual whitelist
};

const limiter = rateLimit({
  windowMs: validatedEnv.RATE_LIMIT_WINDOW * 60 * 1000, // minutes to milliseconds
  max: validatedEnv.RATE_LIMIT_MAX,
  message: 'Too many requests, please try again later.',
});

app.use(helmet());
app.use(cors(corsOptions));
app.use(limiter);

app.use((req: Request, res: Response, next: NextFunction) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  next();
});

export default app;

export interface BaseDTO<T> {
  toDTO(): T;
  fromDTO(dto: T): this;
}

import { createLogger, format, transports } from 'winston';

export const logger = createLogger({
  level: 'info',
  format: format.combine(
    format.timestamp({ format: 'YYYY-MM-DD HH:mm:ss' }),
    format.errors({ stack: true }),
    format.splat(),
    format.json()
  ),
  defaultMeta: { service: 'user-service' },
  transports: [
    new transports.File({ filename: 'error.log', level: 'error' }),
    new transports.File({ filename: 'combined.log' }),
  ],
});

if (process.env.NODE_ENV !== 'production') {
  logger.add(new transports.Console({
    format: format.simple(),
  }));
}
